mapper.select:
SELECT
FROM mall_order o WHERE (o.is_deleted IS NULL OR o.is_deleted = 0) AND o.user_id = #{userId}
AND o.order_status = #{request.orderStatus}
AND o.order_no LIKE CONCAT('%', #{request.orderNo}, '%')
AND EXISTS ( SELECT 1 FROM mall_order_item oi WHERE (oi.is_deleted IS NULL OR oi.is_deleted = 0) AND oi.order_id = o.id AND oi.product_name LIKE CONCAT('%', #{request.productName}, '%') )
ORDER BY o.create_time DESC
